from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Group by subject and build more natural sentences
    sentences = []

    for subject, triples in subject_map.items():
        # Handle airport-specific relationships first
        if "Airport" in subject:
            parts = [subject]

            # Process airport-specific predicates in logical order
            city_served = None
            location = None
            country = None
            elevation = None
            runway_info = []
            other_info = []

            for predicate, obj in triples:
                if predicate == "cityServed":
                    city_served = obj
                elif predicate == "location":
                    location = obj
                elif predicate == "country":
                    country = obj
                elif predicate == "elevationAboveTheSeaLevel":
                    elevation = f"{obj} metres above sea level"
                elif predicate == "elevationAboveTheSeaLevelInFeet":
                    elevation = f"{obj} feet above sea level"
                elif predicate == "runwayLength":
                    runway_info.append(f"runway of {obj} metres")
                elif predicate == "runwayName":
                    runway_info.append(f"runway named {obj}")
                elif predicate == "1stRunwayLengthFeet":
                    runway_info.append(f"first runway of {obj} feet")
                elif predicate == "1stRunwaySurfaceType":
                    runway_info.append(f"first runway with {obj} surface")
                elif predicate == "3rdRunwayLengthFeet":
                    runway_info.append(f"third runway of {obj} feet")
                elif predicate == "3rdRunwaySurfaceType":
                    runway_info.append(f"third runway with {obj} surface")
                elif predicate == "icaoLocationIdentifier":
                    other_info.append(f"ICAO identifier {obj}")
                elif predicate == "iataLocationIdentifier":
                    other_info.append(f"IATA identifier {obj}")
                elif predicate == "locationIdentifier":
                    other_info.append(f"location identifier {obj}")
                elif predicate == "nativeName":
                    other_info.append(f"native name {obj}")
                elif predicate == "operatingOrganisation":
                    other_info.append(f"operated by {obj}")
                elif predicate == "owner":
                    other_info.append(f"owned by {obj}")
                elif predicate == "capital":
                    # Handle capital as a separate relationship
                    pass  # Will be handled in country context
                else:
                    other_info.append(f"{predicate.replace('1stRunway', 'first runway').replace('3rdRunway', 'third runway').replace('Length', ' length').replace('SurfaceType', ' surface type')} of {obj}")

            # Build the sentence with logical flow
            if city_served:
                parts.append(f"serves the city of {city_served}")
                if location:
                    parts.append(f"located in {location}")
                if country:
                    parts.append(f"in {country}")
            elif location:
                parts.append(f"is located in {location}")
                if country:
                    parts.append(f"in {country}")
            elif country:
                parts.append(f"is located in {country}")

            if elevation:
                parts.append(f"with an elevation of {elevation}")

            if runway_info:
                parts.append(f"with {', '.join(runway_info)}")

            if other_info:
                parts.append(f"with {', '.join(other_info)}")

            sentences.append(" ".join(parts))
        else:
            # Handle non-airport entities
            parts = [subject]
            info_parts = []

            for predicate, obj in triples:
                if predicate == "capital":
                    parts.append(f"has a capital of {obj}")
                elif predicate == "country":
                    parts.append(f"is located in {obj}")
                elif predicate == "isPartOf":
                    parts.append(f"is part of {obj}")
                elif predicate == "officialLanguage":
                    parts.append(f"has an official language of {obj}")
                elif predicate == "language":
                    parts.append(f"speaks {obj}")
                elif predicate == "leader":
                    parts.append(f"has a leader of {obj}")
                elif predicate == "leaderParty":
                    parts.append(f"has a leader party of {obj}")
                elif predicate == "mayor":
                    parts.append(f"has a mayor of {obj}")
                elif predicate == "owner":
                    parts.append(f"is owned by {obj}")
                elif predicate == "headquarter":
                    parts.append(f"has its headquarters in {obj}")
                elif predicate == "hubAirport":
                    parts.append(f"has a hub airport at {obj}")
                else:
                    info_parts.append(f"{predicate.replace('1stRunway', 'first runway').replace('3rdRunway', 'third runway').replace('Length', ' length').replace('SurfaceType', ' surface type')} of {obj}")

            if info_parts:
                parts.append(f"with {', '.join(info_parts)}")

            sentences.append(" ".join(parts))

    # Combine all sentences into one complex sentence
    if len(sentences) == 1:
        return sentences[0] + "."
    else:
        # Connect sentences with appropriate conjunctions
        result = sentences[0]
        for i in range(1, len(sentences)):
            # Try to create more natural connections
            if "in " + sentences[i].split()[0] in result or sentences[i].startswith("in "):
                result += " " + sentences[i]
            else:
                result += " which " + sentences[i]
        return result + "."

